{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://github.com/armelhbobdad/bmad-module-skill-forge/src/shared/scripts/schemas/skill-brief.v1.json",
  "title": "skill-brief.yaml (v1)",
  "description": "Canonical schema for the skill-brief.yaml artifact written by skf-brief-skill step 5 and consumed by skf-create-skill, skf-update-skill, skf-audit-skill. Mirrors src/skf-brief-skill/assets/skill-brief-schema.md.",
  "type": "object",
  "required": ["name", "version", "source_repo", "language", "description", "forge_tier", "created", "created_by", "scope"],
  "properties": {
    "name": {
      "type": "string",
      "pattern": "^[a-z0-9]([a-z0-9-]*[a-z0-9])?$",
      "description": "Unique skill identifier (kebab-case)."
    },
    "version": {
      "type": "string",
      "pattern": "^v?\\d+\\.\\d+\\.\\d+([.\\-+][0-9A-Za-z][0-9A-Za-z.\\-+]*)?$",
      "description": "Resolved semver. target_version wins; else auto-detected; else 1.0.0."
    },
    "target_version": {
      "type": "string",
      "pattern": "^v?\\d+\\.\\d+\\.\\d+([.\\-+][0-9A-Za-z][0-9A-Za-z.\\-+]*)?$",
      "description": "User-specified target. When present, MUST equal version."
    },
    "source_type": {
      "type": "string",
      "enum": ["source", "docs-only"]
    },
    "source_repo": {
      "type": "string",
      "minLength": 1,
      "description": "GitHub URL or local path. Required even for docs-only (set to doc site URL)."
    },
    "source_authority": {
      "type": "string",
      "enum": ["official", "community", "internal"]
    },
    "doc_urls": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["url"],
        "properties": {
          "url": { "type": "string", "minLength": 1 },
          "label": { "type": "string" }
        }
      },
      "minItems": 1,
      "description": "Required when source_type is docs-only; allowed as supplemental for source."
    },
    "language": { "type": "string", "minLength": 1 },
    "description": { "type": "string", "minLength": 1 },
    "forge_tier": {
      "type": "string",
      "enum": ["Quick", "Forge", "Forge+", "Deep"]
    },
    "created": {
      "type": "string",
      "pattern": "^\\d{4}-\\d{2}-\\d{2}$"
    },
    "created_by": { "type": "string", "minLength": 1 },
    "scripts_intent": { "type": "string", "minLength": 1 },
    "assets_intent": { "type": "string", "minLength": 1 },
    "scope": {
      "type": "object",
      "required": ["type", "include", "exclude", "notes"],
      "properties": {
        "type": {
          "type": "string",
          "enum": ["full-library", "specific-modules", "public-api", "component-library", "reference-app", "docs-only"]
        },
        "include": { "type": "array", "items": { "type": "string" } },
        "exclude": { "type": "array", "items": { "type": "string" } },
        "notes": { "type": "string" },
        "rationale": {
          "type": "object",
          "description": "Optional authoring-time scope-type decision record written once by skf-brief-skill step 03. Absent on legacy briefs.",
          "required": ["recommended", "chosen", "accepted_recommendation", "heuristic", "reason", "recorded"],
          "additionalProperties": false,
          "properties": {
            "recommended": {
              "type": "string",
              "enum": ["full-library", "specific-modules", "public-api", "component-library", "reference-app", "docs-only"]
            },
            "chosen": {
              "type": "string",
              "enum": ["full-library", "specific-modules", "public-api", "component-library", "reference-app", "docs-only"]
            },
            "accepted_recommendation": { "type": "boolean" },
            "heuristic": { "type": "string", "minLength": 1 },
            "reason": { "type": "string", "minLength": 1 },
            "recorded": { "type": "string", "pattern": "^\\d{4}-\\d{2}-\\d{2}$" }
          }
        }
      }
    }
  }
}
